import React, {useEffect, useState, useRef} from 'react'
import {useParams} from 'react-router-dom'
import {getSingleListing} from '../WebAPI'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import Sidebar from '../components/Sidebar'
import cancel from '../components/static/cancel.png'

const ListingWrapper = styled.div `
display:flex;
width:90%;
justify-content:center;
margin:30px auto;
border:1px solid black;
`

const LeftInfoSection = styled.div `
width:20%;
display:flex;
justify-content:center;
align-items:center;
height:100vh;
border:1px solid black;
`

const ImageSection = styled.div `
width:50%;
border:1px solid black;
`

const Image = styled.div `
width:400px;
height:540px;
border:1px solid black;
background-image:url(${props => props.image ? props.image : null});
background-size:contain;
background-position:center;
background-repeat:no-repeat;
margin:0 auto;
&+& {
	margin-top:20px;
}
`

const RightInfoSection = styled.div `
width:30%;
display:flex;
justify-content:center;
align-items:center;
height:100vh;
border:1px solid black;
`

export default function SingleListing () {
	const {id} = useParams()
	const [listingData, setListingData] = useState([])

	useEffect(() => {
		getSingleListing(id, setListingData)
	},[])

	const listingImage = Object.entries(listingData).filter(data => data[0].indexOf('image') >= 0)

	return (
		<>
			<Header />
			<Navbar />
			<ListingWrapper>
				<LeftInfoSection></LeftInfoSection>
				<ImageSection>
					{listingImage
					.filter(image => image[1] !== null)
					.map(image => <Image key={image[0]} image={image[1]}/>)
					}
				</ImageSection>
				<RightInfoSection></RightInfoSection>
			</ListingWrapper>

		</>
	)
}
